import Rollbar from 'rollbar';
import { LOCAL_DONOR_SESSION_STORAGE_KEY } from './constants';

export const getLocalDonorSession = (rollbar?: Rollbar) => {
  try {
    const item = window.localStorage.getItem(LOCAL_DONOR_SESSION_STORAGE_KEY);

    if (item) {
      return JSON.parse(item);
    }
  } catch (err) {
    rollbar?.error('Unable to restore donor session info', { err });
  }

  return undefined;
};

