import { getLocalDonorSession } from '../localDonorSession/getLocalDonorSession';
import { normalizeOccupation } from '../normalizeOccupation';

const EMPTY: unknown[] = [];

export type ActionPageSubmissionForm = Partial<
  ActionPageSubmission &
    IPaymentMethodForm & {
      customFieldResponsesAttributes: { [key: string]: string };
      employed?: boolean;
      frequency?: string;
      makeDonationAs?: 'individual' | 'organization' | 'pac' | 'business';
