      hasValidDonorPaymentMethod?: boolean;
      hasValidUpgradePaymentMethod?: boolean;
      hideExpressCheckoutControls?: boolean;
      isInUpgradeChain?: boolean;
      pageType: IActionPage['pageType'];
      paymentMethodId?: string;
      savePaymentMethod?: boolean;
    } & {
      futurePledgeDate?: string | null;
      futurePledgeSelected?: boolean;
    } & {
      customFieldPositionsAttributes?: PublicActionPage['fieldConfiguration']['customFieldPositionsAttributes'];
    }
>;

type Props = {
  accountSlug?: string;
  actionPage: PublicActionPage;
  actionPageSlug?: string;
  enableFuturePledgePreCheck?: boolean;
  fundAmountsOverride?: string[];
  fundIdsOverride?: string[];
  isEmbedded: boolean;
  isPreview?: boolean;
  isRestricted?: boolean;
  searchParams: URLSearchParams;
};

export const getActionPageInitialValues = ({
  accountSlug,
  actionPage,
  actionPageSlug,
  enableFuturePledgePreCheck,
  fundAmountsOverride = [],
  fundIdsOverride = EMPTY as string[],
  isEmbedded,
  isPreview = false,
  isRestricted,
  searchParams,
}: Props) => {
  let pageDictionary: Record<string, string> = {};

  const localDonorSession = isPreview ? null : getLocalDonorSession();

  const {
    addressAttributes,
    email,
    employed,
    employerAddressAttributes,
    employerName,
    firstName,
    lastName,
    makeDonationAs,
    middleName,
    occupation,
    organization,
    organizationType,
    phone,
    suffix,
    title,
  } = localDonorSession || {};

  const {
    displayAddress,
    displayEmail,
    displayEmployment,
    displayName,
    displayOrganizationType,
    displayPhone,
    includeEmployerAddress,
    includeEmployerName,
    includeMiddleName,
    includeOccupation,
    includeOrganization,
    includeSuffix,
    includeTitle,
  } = actionPage.fieldConfiguration;

  try {
    pageDictionary = actionPage.pageDictionary ? JSON.parse(actionPage.pageDictionary) : {};
  } catch (_err) {
    pageDictionary = {};
  }

  // find internal names for all custom fields
  const customFieldResponsesAttributes =
    actionPage.fieldConfiguration.customFieldPositionsAttributes?.reduce(
      (acc, cur) => {
        // We bind to customFieldId because all we need for submit is customField and data
        // @ts-ignore
        acc[cur.customFieldAttributes.id] =
          searchParams.get(cur.customFieldAttributes?.internalName ?? '') ??
          pageDictionary[cur.customFieldAttributes?.internalName] ??
          cur.defaultValue ??
          (cur.customFieldAttributes.inputType !== 'requirement' &&
            cur.customFieldAttributes.options.value) ??
          '';
        return acc;
      },
      {} as ActionPageSubmissionForm['customFieldResponsesAttributes']
    );

  let initialAmount =
    (actionPage.amountConfiguration?.amountPresets?.default?.length === 1 &&
    actionPage.pageType === 'donation'
      ? actionPage.amountConfiguration.amountPresets.default[0].amount
      : actionPage.amountConfiguration?.amountPresets?.default?.find((a) => a.default)?.amount) ??
    0;

  const amountAllocationsAttributes: AmountAllocation[] = [];

  if (
    actionPage.fundConfiguration?.multiFundModifiable &&
    fundAmountsOverride.length > 0 &&
    fundIdsOverride.length === fundAmountsOverride.length
  ) {
    fundAmountsOverride.forEach((amount, index) => {
      amountAllocationsAttributes.push({
        actionPagesFundId: fundIdsOverride[index],
        amount: parseFloat(parseFloat(amount).toFixed(2)) * 100,
        fundType:
          actionPage.fundConfiguration?.fundSelectionsAttributes?.find(
            (selection) => selection.fundId === fundIdsOverride[index]
          )?.type ?? '',
      });
    });

    initialAmount = amountAllocationsAttributes.reduce((acc, x) => acc + x.amount, 0);
  }

  const {
    businessDirectDebitEnabled,
    creditCardEnabled,
    paypalEnabled,
    personalDirectDebitEnabled,
