import { PotentialSubmitter } from '@domain/potentialSubmitter';
import { PublicActionPage } from '@domain/publicActionPage';
import { usePotentialSubmitters } from '@state/action_pages/mutations/usePotentialSubmitters';
import { useEffect } from 'react';
import { useFormContext } from 'react-hook-form';
import { useParams } from 'react-router-dom';
import { useDebouncedCallback } from 'use-debounce';
import { useTotalAmount } from '../hooks';

type Props = {
  actionPage: PublicActionPage;
};

export const ActionPagePotentialSubmitter = ({ actionPage }: Props) => {
  const { capturePotentialSubmitter } = usePotentialSubmitters();
  const { watch } = useFormContext();
  const email = watch('email');
  const firstName = watch('firstName');
  const totalAmount = useTotalAmount();

  const { accountSlug } = useParams<{
    accountSlug: string;
  }>();

  const onCapturePotentialSubmitter = useDebouncedCallback(
    (
      potentialSubmitter: PotentialSubmitter,
      publicActionPage: PublicActionPage,
      accountSlugParam?: string
    ) =>
      capturePotentialSubmitter({
        accountSlug: publicActionPage.account.slug,
        actionPageSlug: publicActionPage.slug,
        customDomain: !accountSlugParam ? window.location.hostname : undefined,
        potentialSubmitter,
      }),
    1000,
    { trailing: true }
  );

  useEffect(() => {
    if (!actionPage.recoveryEnabled || !email) {
      return;
    }

    const potentialSubmitter: PotentialSubmitter = {
      details: {
        amount: `${totalAmount}`, // send as cents
      },
      email,
      firstName,
      uri: window.location.href,
    };

    onCapturePotentialSubmitter(potentialSubmitter, actionPage, accountSlug);
  }, [
    accountSlug,
    actionPage,
    actionPage.recoveryEnabled,
    email,
    firstName,
    onCapturePotentialSubmitter,
    totalAmount,
  ]);

  return null;
};

