import { PublicActionPage } from '@domain/publicActionPage';
import { useFeatureFlaggedComponent } from '@utils/useFeatureFlaggedComponent';
import { lazy } from 'react';
import { ActionPageBackground } from './ActionPageBackground';
import { ActionPageBody } from './ActionPageBody';
import { ActionPageFooter } from './ActionPageFooter';
import { ActionPageInfo } from './ActionPageInfo';
import { ActionPageSEO } from './ActionPageSEO';
import { ActionPageTwitterScript } from './ActionPageTwitterScript';
import { ActionPageXPixel } from './ActionPageXPixel/ActionPageXPixel';

const FOTFLayout = lazy(() => import('./FOTFLayout'));
const RestrictedActionPageLayout = lazy(() => import('./RestrictedActionPageLayout'));

const ActionPageLayoutChakra = lazy(() => import('./ActionPageLayoutChakra'));

type ActionPageLayoutProps = {
  actionPage?: PublicActionPage;
  // TS is not smart enough to realize it is in fact used
  isCustomDomain?: boolean;
  isEmbedded?: boolean;
  isRestricted?: boolean;
};

const ActionPageCustomCSS = ({ actionPage }: { actionPage?: PublicActionPage }) => {
  const customCss = actionPage?.generalConfiguration.customCss;
  const insertCustomCss = !!actionPage?.account?.allowCustomCss && !!customCss;

  if (insertCustomCss) {
    return <style>{customCss}</style>;
  }
  return null;
};

const EmbeddedActionPageLayout = ({ actionPage }: ActionPageLayoutProps) => (
  <div className="relative flex w-full flex-grow flex-col items-center justify-stretch overflow-y-auto bg-neutral-0">
    <ActionPageCustomCSS actionPage={actionPage} />
    <ActionPageBody actionPage={actionPage} isEmbedded />
    <ActionPageInfo actionPage={actionPage} />
  </div>
);

export const FullActionPageLayout = ({ actionPage, isCustomDomain }: ActionPageLayoutProps) => {
  const fotfEnabled = actionPage?.account?.accountConfiguration?.fotfEnabled;

  return (
    <div
      className="flex w-full flex-grow flex-col overflow-y-scroll transition-all duration-300 ease-in-out"
      id="content"
    >
      <ActionPageTwitterScript />
      <ActionPageCustomCSS actionPage={actionPage} />
      <ActionPageSEO actionPage={actionPage} />
      <ActionPageXPixel generalConfiguration={actionPage?.generalConfiguration} />
      {fotfEnabled ? (
        <FOTFLayout actionPage={actionPage} isCustomDomain={isCustomDomain} />
      ) : (
        <>
          <ActionPageBackground actionPage={actionPage} />
          <ActionPageBody actionPage={actionPage} isCustomDomain={isCustomDomain} />
        </>
      )}
      <ActionPageFooter actionPage={actionPage} />
      <ActionPageInfo actionPage={actionPage} />
    </div>
  );
};

const ActionPageLayoutTailwind = ({
  actionPage,
  isCustomDomain,
  isEmbedded,
  isRestricted,
}: ActionPageLayoutProps) => {
  return isRestricted ? (
    <RestrictedActionPageLayout actionPage={actionPage} />
  ) : isEmbedded ? (
    <EmbeddedActionPageLayout actionPage={actionPage} isRestricted={isRestricted} />
  ) : (
    <FullActionPageLayout actionPage={actionPage} isCustomDomain={isCustomDomain} />
  );
};

export const ActionPageLayout = (props: ActionPageLayoutProps) => {
  const Component = useFeatureFlaggedComponent(
    'actionPages.chakraRemoval.1',
    ActionPageLayoutTailwind,
    ActionPageLayoutChakra
  );

  return <Component {...props} />;
};

